import 'package:flutter/material.dart'; import '../../../core/theme/app_theme.dart'; class DeviceStatusChip extends StatelessWidget { final bool isOnline; const DeviceStatusChip({super.key, required this.isOnline}); @override Widget build(BuildContext context) => Container(padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4), decoration: BoxDecoration(color: (isOnline ? AppTheme.successColor : Colors.grey).withOpacity(0.1), borderRadius: BorderRadius.circular(20), border: Border.all(color: (isOnline ? AppTheme.successColor : Colors.grey).withOpacity(0.3))), child: Row(mainAxisSize: MainAxisSize.min, children: [Container(width: 6, height: 6, margin: const EdgeInsets.only(right: 6), decoration: BoxDecoration(shape: BoxShape.circle, color: isOnline ? AppTheme.successColor : Colors.grey)), Text(isOnline ? 'Online' : 'Offline', style: TextStyle(color: isOnline ? AppTheme.successColor : Colors.grey, fontSize: 11, fontWeight: FontWeight.w600))])); }